-- =====================================================================
-- #UnitTypeLookup  -- enterprise-wide gold-standard unit classification
-- Source: Unit_Names.xlsx (JupiterGOLD.SM_ADT.Lookup_UnitDefinitions)
-- Filtered: Clarity_ID not null, EndDate > 2022-01-01
-- Generated by medhg_ps.scripts.gen_unit_type_lookup_sql
-- 325 rows across all NYP facilities
-- =====================================================================
IF OBJECT_ID('tempdb..#UnitTypeLookup') IS NOT NULL DROP TABLE #UnitTypeLookup;

CREATE TABLE #UnitTypeLookup (
    Clarity_ID      bigint        NOT NULL,
    Unit_Name       varchar(200)  NOT NULL,
    UnitType        varchar(50)   NOT NULL,
    GNNUnitType     varchar(20)   NOT NULL,
    StartDate       date          NOT NULL,
    EndDate         date          NOT NULL,
    PRIMARY KEY (Clarity_ID, StartDate)
);


CREATE NONCLUSTERED INDEX IX_UnitLookup_ClarityID ON #UnitTypeLookup (Clarity_ID);
